#include <stdio.h>
#include <string.h>

int main() {
    int a;
    scanf("%d", &a);
    int summ = 5;
    while (summ % 4 != 0) {
        summ = 0;
        char str[20];
        sprintf(str, "%d", a);
        for (int i = 0; i < strlen(str); i++) {
            summ += str[i] - '0';
        }
        if (summ % 4 != 0) {
            a++;
        }
    }
    printf("%d\n", a);
    return 0;
}
